import (
	context "context"
	fern "github.com/mixed-file-directory/fern"
	fernclient "github.com/mixed-file-directory/fern/client"
)

client := fernclient.NewClient()
response, err := client.Organization.Create(
	context.TODO(),
	&fern.CreateOrganizationRequest{
		Name: "name",
